export class ApiService {
  constructor(
    public readonly url: string,
    private token: string
  ) {}

  getAuthHeader(): string {
    return `Bearer ${this.token}`;
  }
}
const api = new ApiService('http://api.com', 'xyz123');

test_script:
if (!api || typeof api.getAuthHeader !== 'function') throw new Error('Instancia no válida');
if (api.url !== 'http://api.com') throw new Error('La propiedad url no es pública o no está asignada');
if (api.getAuthHeader() !== 'Bearer xyz123') throw new Error('El método getAuthHeader() falla');

